var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MEMBER_HARMONY_NULL_NULL","text":{"KOREA":"아아……! 아아아아아악!!","JPN":"ああ……！　ああああああっ！！","ENG":"Ah...! AAAAAHHHHH!!!","TWN":"啊啊……！啊啊啊啊啊啊！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여기 너를 위해 예비된 단두대가 왔으니, 안식에 들도록 하라.","JPN":"ここに貴様のために準備された断頭台がある、安息に入れ。","ENG":"This guillotine has been reserved for you. You shall rest in peace.","TWN":"這是為你而準備的斷頭台，進入安息吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_HARMONY_NULL_NULL","text":{"KOREA":"후후, 후흐흐흐흐……!","JPN":"ふふ、ふふふふふ……！","ENG":"Hu hu... Hu hu hu hu hu...!","TWN":"呵呵，呵呵呵呵呵……！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님께서 돌아오셨다……! 그분께서 우리의 염원을……!","JPN":"マエストロがお戻りだ……！　あの方が我々の願いを……！","ENG":"Chief Conductor has returned...! She will grant our wishes–!","TWN":"指揮家回來了……！她會把我們的願望……！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이 침식체들은 전부 유언이 길군요.","JPN":"この侵食体はみんな遺言が長いですね。","ENG":"All these C.O.s talk too much.","TWN":"這些侵蝕體的遺言全都很長啊。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"음성 저장할 공간이 부족하니 곱게 죽어 주는 편이 좋습니다만.","JPN":"音声を保存するための容量が足りないので、大人しく死んでくれるとありがたいのですが。","ENG":"I'm running out of storage for audio, so it'd be nice if they just died without saying anything.","TWN":"保存語音的空間不足，還是死得漂亮點更好。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……핵이 파괴되었으니, 두 번 다시 이 세계에 모습을 비추지는 않을 터.","JPN":"……彼らは核が破壊されている。二度とこの世界に姿を現せまい。","ENG":"Their cores have been destroyed. They will never show their faces on this world again.","TWN":"……她們核心被破壞了，不會再出現在這個世界上了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"실로 훌륭한 무용이로다.","JPN":"実に素晴らしい武勇だ。","ENG":"An excellent display of valor.","TWN":"你的勇猛無人能敵。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 저장 공간에는 아직 그 시기의 영상이 존재합니다. 침식체.","JPN":"私のメモリには、まだあの頃の映像が存在します。侵食体。","ENG":"I still store the video of that day, C.O.","TWN":"我的存儲空間裡還有那個時期的影像，侵蝕體。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대의 동료들에 대해서는……","JPN":"そなたの仲間については……","ENG":"About what happened to your colleagues...","TWN":"對於你的同伴……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 이상 발언하지 마십시오.","JPN":"それ以上の発言はおやめください。","ENG":"You do not speak anymore.","TWN":"請不要再說下去了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 당신과 목표 달성을 위해 일시적으로 협조하고 있을 뿐입니다.","JPN":"私はあなたと目標達成のために一時的に協力しているだけです。","ENG":"This is a temporary alliance because our objectives line up.","TWN":"我和你只是為了達成目標，暫時合作而已。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 불필요한 발언은 하지 마십시오.","JPN":"ですので、不要な発言は慎んでください。","ENG":"So avoid making any unnecessary remarks.","TWN":"所以，請不要發表不必要的言論。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이 시점에 적대 관계를 형성하는 행위는 서로에게 비합리적인 선택이 될 것입니다.","JPN":"この時点で敵対関係を形成する行為はお互いに非合理的な選択になるでしょう。","ENG":"Turning me into your enemy at this point will be inefficient for the both of us.","TWN":"在這個時候做出形成敵對關係的行為，對彼此來說都是不合理的選擇。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……알겠다. 그대의 뜻을 존중하지.","JPN":"……よかろう。そなたの意思を尊重しよう。","ENG":"...Understood. I will do as you say.","TWN":"……知道了。我尊重你的意思。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐시기 침식체! 침묵 확인! 이걸로 기분 나쁜 연주랑은 안녕이야!","JPN":"何とか侵食体！　沈黙を確認！　これで気持ち悪い演奏とはおさらばだね！","ENG":"Whatchamacallit C.O.! Kill confirmed! Now it's bye-bye to that creepy music!","TWN":"那個什麼侵蝕體！確認沉默！用這個告別讓人不愉快的演奏吧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼, 평범하게 말하십시오. 교육 받은 오퍼레이터들과 1%도 일치하지 않습니다.","JPN":"レイチェル、普通に話しなさい。教育を受けたオペレーターと1％も一致していません。","ENG":"Rachel, speak normally. Your speech pattern is not even 1% compatible with that of trained operators.","TWN":"瑞秋，請你說話正常點。和其他受訓的領航員連1%都不一樣。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"에이, 모처럼 함교에 앉아서 분위기 좀 잡았더니……","JPN":"ええ～？　せっかくブリッジに座ってそれっぽい雰囲気を演出しようとしてたのに……","ENG":"Oh, come on. I was just having some fun from the bridge...","TWN":"哎呀，我好不容易坐到艦橋上感受下氛圍……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"고생했어, 호라이즌.","JPN":"お疲れ様、ホライズン。","ENG":"Good job, Horizon.","TWN":"辛苦你了，地平線。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"예. 제가 부재 중인 동안 다른 일은 없었습니까?","JPN":"はい。私の不在中に変わったことはありませんでしたか？","ENG":"Yes. Did anything else happen while I was gone?","TWN":"嗯，我不在的這段時間沒有別的事嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 맞다. 팬드래건 씨에게서 연락이 왔어. 꼭 해야 할 말이 있대.","JPN":"あ、そうだ。ペンドラゴンさんから連絡があったよ。絶対話さなきゃいけないことがあるって。","ENG":"Oh, right! Ms. Pendragon called. She said she had something important to say.","TWN":"啊，對了。潘德拉貢來電話了，她說有話要和你說。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"리퍼 인더스트리제 윤활유도 구해 뒀으니까 얼른 돌아오도록! 이상~!","JPN":"リーファー・インダストリー製の潤滑油も手に入れたから、早く帰還するように！　以上～！","ENG":"I also procured some lubricant from Reaper Industries, so come back soon! Over and out!","TWN":"收割者的潤滑油也買好了，快點回去吧！完畢～！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 입력 장치에 문제가 생긴 모양이군요.","JPN":"私の入力装置に問題が発生したようですね。","ENG":"There's something wrong with my input device.","TWN":"我的輸入裝置好像出問題了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"다시 말씀해 주십시오. 방금 뭐라고 지껄였습니까, 휴먼?","JPN":"もう一度お願いします。今なんと？　ヒューマン。","ENG":"Please repeat. What did you blabber just now, human?","TWN":"請再說一遍。你剛才說了什麼，人類？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬 기관은 엘리시움 필하모닉의 추적을 잠정적으로 중단한다고 했답니다. 깡통.","JPN":"プリドウェン機関はエリシウムフィルハーモニーの追跡を暫定的に中断すると言ったのですわ。ボロ缶。","ENG":"Prydwen Institution is temporarily suspending the tracking of Elysium Philharmonic. Tin can.","TWN":"普利多溫機關說要暫停對愛樂組織的追蹤，鐵桶。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 쓰레기 데이터를 발생시키는 건 그 나약한 중추신경입니까, 단백질 덩어리.","JPN":"そのようなクズデータを発生させているのは、その軟弱な中枢神経ですか？　タンパク質の塊。","ENG":"Is it your frail central nerve that generates such garbage data, you mishmash of malleable proteins?","TWN":"產生那種垃圾資料的是那些懦弱的中樞神經嗎，蛋白質塊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"양산도 안 되고 단종된 제품 주제에 말귀까지 못 알아들으시네요. 고철 덩어리.","JPN":"量産もできずに製造中止になった製品のくせに、耳までイカれたのですね。クズ鉄の塊。","ENG":"You non-mass-produced, discontinued piece of scrap metal. Is something wrong with your hearing as well now?","TWN":"連量產都不行的破爛斷貨產品，現在連人話都聽不懂了呢，廢鐵塊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하. 자, 자. 아가씨. 친구를 사귀시는 건 좋지만 싸움은 안 됩니다.","JPN":"はは。さあ、さあ。お嬢様。お友達を作るのはよろしいのですが、ケンカはいけません。","ENG":"Haha. Now, now, my lady. It's good to make friends, but not to fight.","TWN":"哈哈，好了，好了，小姐。交朋友固然好，但是不可以吵架。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 군도 그렇고 솔직하지 못하게 대할수록 나중에 사과하기 피곤해지거든요.","JPN":"バーネット君もそうですが、素直でない態度を取ると後で謝る時に苦労しますよ。","ENG":"As it was with Burnett, the more deceptive you are, the more difficult it will be to apologise later.","TWN":"伯內特也是，如果不能以誠相待，以後就會有很多要道歉的事情發生。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"사, 사람들 앞에서 애 다루듯 하지 마세요! 누가 친구라는 거예요?","JPN":"ほ、他の人の前で子ども扱いしないでください！　誰が友達ですか！","ENG":"S-stop treating me like a child in front of others! And who's friends with whom?!","TWN":"不…不要在別人面前拿我當小孩子！你說誰是朋友？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어이쿠, 이런. 그렇게 몸부림치시면 다친 데가 덧납니다.","JPN":"おっと。そう暴れますと、怪我がこじれます。","ENG":"Oh my! If you keep writhing like that, your wounds will not heal properly.","TWN":"哎呦，真是的。如果你繼續掙扎，受傷的地方會加重。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"긍정. 저도 그런 말랑말랑한 관계는 거부하겠습니다.","JPN":"肯定。私もそのようなふわふわした関係はお断りします。","ENG":"Affirmation. I also refuse this squishy relationship.","TWN":"正確，我也拒絕那種軟綿綿的關係。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"에이, 서로 죽도 잘 맞으면서 왜 그래.","JPN":"え～？　お互いよく気も合ってるのになんで～。","ENG":"Oh, come on. You two were getting along so well!","TWN":"欸，我們明明很合得來，你幹嘛這樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"말하지 않았던가. 마에스트로를 추격하지 않는다면 나 역시 너희와 함께할 까닭이 없다.","JPN":"言ったであろう。マエストロを追撃しないなら、我もまたそなたたちに協力する理由はない。","ENG":"Didn't I say? If you are not tracking Maestra, then I have no reason to continue on with you.","TWN":"我不是說過了嗎。如果不是追擊指揮家，我也沒有理由和你們合作。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이미 그 그림자도 모자라 수훈자라는 소녀마저 이탈했을 터.","JPN":"すでにあのシャドウも、受勲者である少女も離脱したはず。","ENG":"Even both that Shadow and the Medal of Honor girl have already fled.","TWN":"光是那個暗影還不夠，現在連受勳的少女都離開了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"어렵게 모인 전력을 분산시켜 어찌할 셈인가.","JPN":"ようやく集まった戦力を分散して、どうするつもりだ？","ENG":"What are your plans by dispersing what little man power you have left?","TWN":"分散好不容易聚集起來的戰鬥力，你到底想要做什麼。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……각자 소임을 다하고 있다고 해 주시죠.","JPN":"……各自の役割を果たしていると言ってください。","ENG":"...Let's just say we're all doing our part.","TWN":"……應該說是各司其職吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오히려 제 쪽에서 묻고 싶군요.","JPN":"むしろ、私の方からお聞きしたいですわ。","ENG":"But I should ask you the same.","TWN":"我倒是想問問你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"경험자로서, 수적으로 우세를 점한다고 그 5종 침식체를 격퇴할 수 있나요?","JPN":"経験者として、数的に優勢だからといって、あの第5種侵食体を撃退することが可能なのですか？","ENG":"As one with experience, do you believe that a numerical advantage will be enough to defeat that Category 5 C.O.?","TWN":"作為戰鬥的經歷者，你覺得在數量上佔優勢就能擊退那個5類侵蝕體嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"필요한 퍼즐 조각이 모이지 않으면 불가능해요. 적은 그런 존재입니다.","JPN":"必要なピースが揃わなければ無理ですわ。敵はそんな存在です。","ENG":"Without the necessary puzzle pieces, it will be impossible. That is who we are up against.","TWN":"如果沒有收集到必須拼圖碎片，就不可能。敵人就是那樣的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"알고 있다.","JPN":"わかっている。","ENG":"I am fully aware.","TWN":"我知道。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 확신할 수 있을 시기에 다다랐을 때는…… 이미 모든 것이 늦은 뒤일 터.","JPN":"だが確信できる段階になったときには……もうすべてが手遅れとなっているだろう。","ENG":"But when the moment of certainty comes... it will all be too late.","TWN":"可是等到確定能打贏的時候……一切可能都太遲了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우려하는 지점은 저도 어느 정도 동감한다고 해야겠군요.","JPN":"ご心配の部分については、私も同感するところがあります。","ENG":"I must say that I agree to some extent of your concern.","TWN":"應該說在某種程度上，你擔心的部分我也贊同。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 저희에게도 해야 할 일들의 우선 순위가 존재한답니다.","JPN":"ですが、私たちにもやるべきことの優先順位というものが存在するのです。","ENG":"We do, however, have priorities for what needs to be done.","TWN":"不過我們要做的事情也是有優先順序的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"류드밀라 언니는 전력이 필요한 곳이 있다고 했지?","JPN":"リュドミラ姉さんは、戦力が必要なところがあるって言ってたよね？","ENG":"Lyudmila is right where she needs to be, right?","TWN":"你說需要盧德米拉姊姊的戰鬥力對吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그럼 퍼즐을 모은다는 건, 혹시 크리스가……?","JPN":"じゃあピースを集めるってのは、もしかしてクリスが……？","ENG":"Then the puzzle piece you're talking about is... Is it Chris?","TWN":"那收集拼圖的事，難道是克莉絲……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 일단은 국가적인 영웅이니 말이죠.","JPN":"はい。一応は国家的英雄ですから。","ENG":"Yes. She is a national hero after all.","TWN":"是的，她是國家英雄。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"집결하지 못한 단원들을 색출해내는 것도, 저들이 구축했던 시설들을 파괴하는 것도.","JPN":"集結できなかった団員を捜索するのも、彼らが構築した施設を破壊するのも。","ENG":"Finding the Elysium members who were unable to assemble and destroying the facilities they had built...","TWN":"找出沒能招聚的團員，破壞他們建造的設施，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"심의회를 끌어들이는 것도.","JPN":"審議会を巻き込むのも。","ENG":"And even attracting the Investigation Council...","TWN":"還有將議會牽扯進來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전부 한 번의 성공을 위한 기반에 지나지 않습니다.","JPN":"すべては一度の成功のための基盤に過ぎません。","ENG":"They are all the foundations for this one shot.","TWN":"全都是為了能夠一次成功，做的基本預備而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"브레히트 중사가 소임을 마치고 귀환한다면, 5종 침식체의 격퇴도 꿈은 아니에요.","JPN":"ブレヒト軍曹が任務を果たして帰還したら、第5種侵食体の撃退も夢物語ではありません。","ENG":"If Sergeant Brecht returns from her duties, defeating that Category 5 C.O. will not be a pipe dream.","TWN":"如果布萊希特中士能完成任務回來，擊退5類侵蝕體也不再是夢想。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에  호라이즌 당신이 제 성능만 발휘했어도 이렇게 복잡하게 처리할 일이 아니었겠지만요.","JPN":"そもそもホライズン、あなたが本来の性能を発揮していたら、これほど複雑な形で処理するようなことではなかったのですけど。","ENG":"Horizon, if you could have done your best, things wouldn't have been so complicated in the first place.","TWN":"如果一開始地平線你能充分發揮自己的性能，就不用處理這麼複雜的情況了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아쉬우면 업그레이드라도 지원해 주시죠. 혹시 라디오는 제작해 본 적 있습니까?","JPN":"悔しかったらアップグレードでも支援してください。ラジオを製作してみたことはありますか？","ENG":"Then why don't you fund my upgrades? Oh, wait. Have you even assembled a radio before?","TWN":"覺得可惜的話，就幫我升級吧。你製作過收音機嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"에휴, 너도 참 그 까칠한 성격 고쳐야 한다니까……","JPN":"もう、あんたもそのトゲトゲした性格を直した方がいいって……","ENG":"Ugh... You really need to fix that personality of yours...","TWN":"唉，你也該改改那尖銳的性格了……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저, 그냥 무슨 일 때문에 중단해야 하는지 알려 주시면 안 돼요?","JPN":"あの、なんで中断しなきゃいけないのか教えてくれませんか？","ENG":"Um, could you just tell us why you have to put everything on hold for now?","TWN":"那個，不能告訴大家是因為什麼事才要中斷的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"납득이 갈 만한 이유라면 다들 이해해 줄지 모르잖아요.","JPN":"納得できる理由なら、みんな理解してくれるかも知れないでしょ？","ENG":"I'm sure they'll all understand if the reasoning is convincing enough.","TWN":"如果是有說服力的理由，說不定大家都會理解。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아요. 국가 기밀이지만, 여러분이 관련되신 사태도 그에 못지 않군요.","JPN":"いいですわ。国家機密ですが、皆さんが巻き込まれている事態も似たようなものですものね。","ENG":"Very well. This is classified, but then again, so is your current situation.","TWN":"好吧，雖然是國家機密，但同樣也是涉及到大家的事態。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 다들 이해해 줘서 다행이군요. 아량이 넓은 친구 분들을 사귀셨습니다.","JPN":"ですが、皆さんが理解してくれて何よりですな。心の広いお友達です。","ENG":"I am glad that they understood. You've made some generous friends, my lady.","TWN":"不過好在大家都能理解。你結交了一群心胸寬廣的朋友呢。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"걱정되십니까, 아가씨.","JPN":"ご心配ですか？　お嬢様。","ENG":"Are you worried, my lady?","TWN":"你擔心嗎，小姐。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 합중국에서 감지된 수상한 동향……","JPN":"はい。合衆国で感知された怪しい動き……","ENG":"Yes. The suspicious activities detected from the States...","TWN":"是的，在合眾國察覺到的可疑動向……"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 학회의 목적이 정말 합중국이었다면, 교수 역시 최대한 발각되지 않게 움직였겠죠.","JPN":"そもそも学会の目的が本当に合衆国だったのなら、教授もなるべく発覚されないように動いたはずですわ。","ENG":"The Professor would have moved quietly to avoid detection if the Society was truly after the States.","TWN":"如果一開始學會的目的真是合眾國，那教授也會儘量避免被發現吧。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 어떻게 생각해도 저희를 꾀어내기 위한 술책이에요.","JPN":"これはどう考えても私たちをおびき寄せるための企みです。","ENG":"This all seems like a ploy to lure us out, no matter how I think about it.","TWN":"我想來想去，都覺得這是誘騙我們的伎倆。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"여왕 폐하께 몇 번이고 진언을 드렸지만…… 정치는 아직 제 영역이 아니네요.","JPN":"女王陛下に何度も進言いたしましたが……政治はまだ私の領域ではありませんね。","ENG":"I've messaged Her Majesty time and time again, but... politics don't seem to be my strong suit.","TWN":"我雖然多次向女王陛下進言……但政治不是我的領域。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"흔들리시면 안 됩니다, 아가씨.","JPN":"惑わされてはいけません、お嬢様。","ENG":"You must not be swayed, my lady.","TWN":"你不可以動搖，小姐。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>오래된 목소리</color>도 경고했죠. 게임이 시작될 거라고.","JPN":"<color=#ffd34c>古い声</color>も警告しました。ゲームが始まると。","ENG":"The <color=#ffd34c>Old Voice</color> also warned us... That the game will soon begin.","TWN":"<color=#ffd34c>老聲音</color>也警告說，遊戲就要開始了。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"현장에서는 항상, 희생을 각오하고 있습니다.","JPN":"現場では常に、犠牲を覚悟しております。","ENG":"On the field, we are always ready to sacrifice.","TWN":"在現場，要始終做好犧牲的準備。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어쩌면 이번에는…… 더 큰 희생을 치러야 할지도 모르죠.","JPN":"もしかすると今度は……より多くの犠牲を払わねばならないかもしれません。","ENG":"Perhaps this time... We may have to make more sacrifices.","TWN":"說不定這次……還要做出更大的犧牲。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"봉인 시설들에 경계를 강화하라고 해 두세요.","JPN":"隔離施設に警戒を強めるように伝えてください。","ENG":"Tell them to enhance the security of the quarantine facilities.","TWN":"告訴隔離設施加強警戒。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 모건, 당장 호라이즌 측에게로 합류를 부탁드리겠습니다.","JPN":"そしてモーガン、今すぐホライズン側に合流してください。","ENG":"And Morgan, please join the Horizon team right away.","TWN":"還有，摩根，馬上去地平線那邊會合。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이런, 부상당한 참에 아예 이 늙은이를 내치실 작정이십니까.","JPN":"そんな、俺が怪我したのをいいことに、この老体を追い出してしまうおつもりですか？","ENG":"Oh my, are you going to abandon this old man just because he is wounded?","TWN":"哎呀，你是想趁我受傷了，乾脆甩開我這個老傢伙嗎？"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"언제 사고를 칠지 모르는 작자들이니까요.","JPN":"いつ何をしでかすかわからない連中ですから。","ENG":"They are hooligans who could cause trouble at a moment's notice.","TWN":"因為那群人不知道什麼時候就會闖禍。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……제가 없는 동안, 잘 부탁드려요.","JPN":"……私がいない間、よろしくお願いします。","ENG":"...Please watch over them while I am away.","TWN":"……我不在的時候，就拜託你了。"},"stage":{"bg":"CAFE","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};